import pyotp
import qrcode
from io import BytesIO

def generate_totp_secret():
    return pyotp.random_base32()

def generate_qr_code(secret, user_email):
    otp = pyotp.TOTP(secret)
    qr = qrcode.QRCode(
        version=1,
        error_correction=qrcode.constants.ERROR_CORRECT_L,
        box_size=10,
        border=4,
    )
    qr.add_data(f"otpauth://totp/{user_email}?secret={secret}")
    qr.make(fit=True)
    img = qr.make_image(fill='black', back_color='white')
    img_io = BytesIO()
    img.save(img_io, 'PNG')
    img_io.seek(0)
    return img_io

def validate_totp_code(secret, code):
    otp = pyotp.TOTP(secret)
    return otp.verify(code)

# Example usage
user_email = "example@example.com"
secret = generate_totp_secret()
qr_code = generate_qr_code(secret, user_email)
print("TOTP Secret:", secret)
print("QR Code URL:", qr_code.getvalue())

# Simulate TOTP code validation
input_code = input("Enter TOTP code: ")
if validate_totp_code(secret, input_code):
    print("TOTP code is valid.")
else:
    print("TOTP code is invalid.")